		}
		if strings.Contains(bodyStr, "Task: seq task b") {
			mu.Lock()
			callOrder = append(callOrder, "b")
			mu.Unlock()
			_, _ = w.Write([]byte(`{
				"id": "msg_b", "type": "message", "role": "assistant",
				"content": [{"type": "text", "text": "seq result b"}],
				"model": "claude-sonnet-4-20250514", "stop_reason": "end_turn",
