	}

	output := buf.String()
	if !strings.Contains(output, "The file says: Hello, World!") {
		t.Errorf("expected stdout to contain final response, got %q", output)
	}

	if mock.RequestCount() != 2 {
		t.Errorf("expected 2 requests, got %d", mock.RequestCount())
