	err := rootCmd.Execute()
	if err != nil {
		t.Fatalf("expected nil error, got: %v", err)
	}

	if mock.RequestCount() != 4 {
		t.Errorf("expected 4 requests, got %d", mock.RequestCount())
	}

	output := buf.String()
