	writeAgentConfig(t, configDir, "verbose-tools", `name = "verbose-tools"
model = "anthropic/claude-sonnet-4-20250514"
tools = ["read_file"]
`)

	workdir := t.TempDir()
	if err := os.WriteFile(filepath.Join(workdir, "test.txt"), []byte("line one\nline two"), 0644); err != nil {
